#include <bits/stdc++.h>
using namespace std;
const int N=3003;
struct Edge{
	int to,val;
};
int n,m,val[N],siz[N],f[N][N];
vector<Edge> g[N];
void dfs(int x){
	f[x][0]=0;
	if(x>n-m){
		f[x][1]=val[x],siz[x]=1;
		return;
	}
	int len=g[x].size();
	for(int i=0;i<len;i++){
		dfs(g[x][i].to);
		siz[x]+=siz[g[x][i].to];
		for(int j=siz[x];j;j--)
			for(int k=1;k<=min(j,siz[g[x][i].to]);k++)
				f[x][j]=max(f[x][j],f[x][j-k]+f[g[x][i].to][k]-g[x][i].val);
	}
}
int main(){
	scanf("%d%d",&n,&m);
	for(int i=1,k;i<=n-m;i++){
		scanf("%d",&k);
		while(k--){
			int a,c;
			scanf("%d%d",&a,&c);
			g[i].push_back({a,c});
		}
	}
	for(int i=1;i<=m;i++)
		scanf("%d",&val[n-m+i]);
	memset(f,0xcf,sizeof(f));
	dfs(1);
	for(int i=m;i>=0;i--)
		if(f[1][i]>=0){
			printf("%d",i);
			break;
		}
	return 0;
}
